package com.cognizant.gateway.config;import org.springframework.cloud.gateway.filter.ratelimit.KeyResolver;import org.springframework.context.annotation.*;import reactor.core.publisher.Mono;@Configuration public class RateLimiterConfig{@Bean KeyResolver ipKeyResolver(){return exchange->Mono.justOrEmpty(exchange.getRequest().getRemoteAddress()).map(a->a.getAddress().getHostAddress()).defaultIfEmpty("unknown");}}